using namespace std;
il ll read()
{
    ll x=0,f=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=getchar();}
    return x*f;
}
void write(ll x)
{
    if(x<0)putchar('-'),x=-x;
    if(x>9)write(x/10);
    putchar(x%10+'0');
}
void writeln(ll x)
{
    write(x);
    puts("");
    return;
}
CI MAXN=1e5/3+5;
int f[MAXN],a[25],m,n,cnt,sum=0;
string s;
int main(void)
{
	//freopen("in.txt","r",stdin);
	//freopen("out.txt","w",stdout);
	n=read();
	FOR(i,1,n)
    {
        a[i]=read();
    }
    m=read();
	cin>>s;
    s=' '+s;
	FOR(i,1,m/3)
	{
        FOR(j,1,min(n,i))
		{
		    f[i]=max(f[i],f[i-j]+a[j]);
        }
    }
	FOR(i,3,m)
    {
		while(i<=m&&s[i]=='c'&&s[i-1]=='b'&&s[i-2]=='a'&&++cnt)
        {
            i+=3;
        }
		sum+=f[cnt];
        cnt=0;
	}
    writeln(sum);
	return false;
}
